const CETASIKA_DATA = [{"id": "xuc", "ten": "Xúc", "pali": "Phassa", "nhom": "bienhanh", "giaithich": "Gặp gỡ giữa tâm, môn/căn và cảnh — nền tảng để tâm tiếp xúc với đối tượng. Có mặt trong mọi tâm vì bất kỳ tâm nào sinh khởi cũng cần có sự tiếp xúc với cảnh."}, {"id": "tho", "ten": "Thọ", "pali": "Vedanā", "nhom": "bienhanh", "giaithich": "Cảm thọ cảnh: lạc, khổ, hỷ, ưu, xả. Mọi tâm khi sinh khởi đều phải mang theo một trong 5 loại cảm thọ này — không thể có tâm nào hoàn toàn không có cảm thọ."}, {"id": "tuong", "ten": "Tưởng", "pali": "Saññā", "nhom": "bienhanh", "giaithich": "Nhận dấu hiệu, ghi nhận đặc điểm của cảnh để nhận ra sau này. Có mặt cả trong ngũ song thức (những tâm đơn giản nhất) vì ngay cả nhận biết thô sơ cũng cần đánh dấu cảnh."}, {"id": "tu", "ten": "Tư", "pali": "Cetanā", "nhom": "bienhanh", "giaithich": "Chủ ý, điều phối các tâm sở đồng sinh hướng về một mục tiêu; là yếu tố tạo nghiệp khi có mặt trong tâm đổng lực (javana)."}, {"id": "nhattam", "ten": "Nhất tâm", "pali": "Ekaggatā", "nhom": "bienhanh", "giaithich": "Tụ họp, giữ tâm và các tâm sở đồng sinh không tán loạn, cùng gắn trên một cảnh duy nhất."}, {"id": "mangquyen", "ten": "Mạng quyền (danh)", "pali": "Jīvitindriya", "nhom": "bienhanh", "giaithich": "Duy trì sự tồn tại của danh pháp (tâm và các tâm sở khác) đồng sinh trong cùng sát-na — tương ứng phần Danh mạng quyền trong 22 Quyền."}, {"id": "tacy", "ten": "Tác ý", "pali": "Manasikāra", "nhom": "bienhanh", "giaithich": "Hướng tâm và các pháp đồng sinh đến đối tượng — như bánh lái điều hướng con thuyền tâm thức."}, {"id": "tam", "ten": "Tầm", "pali": "Vitakka", "nhom": "toitha", "giaithich": "Hướng/đưa tâm đến cảnh lần đầu. Vắng mặt trong 10 tâm Ngũ song thức (vì các tâm này quá đơn giản, chưa cần \"nhắm\" vào cảnh) và vắng mặt từ tầng thiền thứ 2 trở lên (vì thiền càng cao càng vi tế, không cần thao tác thô của Tầm nữa).", "socount": 55, "quyluat": "121 tâm trừ 10 Ngũ song thức, trừ tiếp các tâm thiền từ tầng 2 trở lên (chỉ còn ở tầng Sơ thiền)."}, {"id": "tu2", "ten": "Tứ", "pali": "Vicāra", "nhom": "toitha", "giaithich": "Giữ tâm quan sát, \"xoay quanh\" cảnh sau khi Tầm đã hướng đến. Vắng mặt ở Ngũ song thức (cùng lý do với Tầm) và vắng từ tầng thiền thứ 3 trở lên.", "socount": 66, "quyluat": "121 tâm trừ 10 Ngũ song thức, trừ các tâm thiền từ tầng 3 trở lên (còn ở Sơ thiền và Nhị thiền)."}, {"id": "thangiai", "ten": "Thắng giải", "pali": "Adhimokkha", "nhom": "toitha", "giaithich": "Xác định, quyết đoán dứt khoát về cảnh — như người phán quyết dứt điểm. Vắng mặt ở Ngũ song thức (chưa đủ điều kiện quyết đoán) và vắng ở tâm Si hợp hoài nghi (vì bản chất hoài nghi chính là không thể quyết đoán được).", "socount": 110, "quyluat": "121 tâm trừ 10 Ngũ song thức và trừ 1 tâm Si hợp hoài nghi."}, {"id": "can", "ten": "Cần", "pali": "Viriya", "nhom": "toitha", "giaithich": "Nỗ lực, siêng năng thúc đẩy các pháp đồng sinh hoàn thành nhiệm vụ. Vắng mặt ở phần lớn tâm Vô nhân (vì đây là những tâm quả/thụ động, không cần nỗ lực) — chỉ có mặt ở 2 tâm Vô nhân chủ động là Hướng ý môn và Sinh tiếu.", "socount": 105, "quyluat": "121 tâm trừ 15 tâm Quả Vô nhân (thụ động) và trừ 1 tâm Hướng ngũ môn (dù là Duy tác nhưng chỉ làm nhiệm vụ hướng tâm đơn thuần, chưa cần nỗ lực)."}, {"id": "hy", "ten": "Hỷ", "pali": "Pīti", "nhom": "toitha", "giaithich": "Sự hoan hỷ, phấn khởi, làm cho thân tâm sung mãn — chỉ đồng sinh với các tâm có cảm thọ Hỷ (somanassa), không thể có mặt cùng tâm thọ Xả/Khổ/Ưu.", "socount": 51, "quyluat": "18 tâm Dục giới thọ hỷ (gồm 4 tham thọ hỷ hợp/ly tà kiến ×asankharika+sasankharika=8? xem chi tiết, cộng tâm quả/duy tác thọ hỷ) + 33 tâm Sơ, Nhị, Tam thiền (Hỷ chỉ còn tới tầng thiền thứ 3, mất từ tầng 4)."}, {"id": "duc", "ten": "Dục (mong muốn làm)", "pali": "Chanda", "nhom": "toitha", "giaithich": "Ý muốn thực hiện, mong muốn tác động lên cảnh — khác với Tham (Lobha) là sự dính mắc. Vắng mặt ở tâm Vô nhân (các tâm này không có ý chí hành động) và vắng ở 2 tâm Si (Si vốn mê mờ, không có ý muốn rõ ràng để làm gì).", "socount": 101, "quyluat": "121 tâm trừ 18 tâm Vô nhân và trừ 2 tâm Si."}, {"id": "si", "ten": "Si", "pali": "Moha", "nhom": "batthien_bh", "giaithich": "Không biết rõ bản chất thực của cảnh — gốc rễ của mọi bất thiện. Luôn có mặt trong cả 12 tâm bất thiện, kể cả tâm Tham hay Sân, vì bất kỳ tâm bất thiện nào cũng hàm chứa một mức độ mê mờ nào đó."}, {"id": "votam", "ten": "Vô tàm", "pali": "Ahirika", "nhom": "batthien_bh", "giaithich": "Không hổ thẹn khi làm điều tội lỗi — luôn đi cùng Si trong mọi tâm bất thiện."}, {"id": "voquy", "ten": "Vô quý", "pali": "Anottappa", "nhom": "batthien_bh", "giaithich": "Không ghê sợ hậu quả của tội lỗi — luôn đi cùng Vô tàm và Si trong mọi tâm bất thiện."}, {"id": "phongdat", "ten": "Phóng dật", "pali": "Uddhacca", "nhom": "batthien_bh", "giaithich": "Tâm không yên, xao động, tán loạn trên cảnh — có mặt trong toàn bộ 12 tâm bất thiện (kể cả khi nó cũng chính là chi pháp của tâm Si hợp phóng dật)."}, {"id": "tham", "ten": "Tham", "pali": "Lobha", "nhom": "batthien_rieng", "giaithich": "Dính mắc, bám víu vào cảnh — chi pháp riêng của 8 tâm Tham. Không thể đồng sinh với Sân trong cùng một sát-na vì bản chất trái ngược (dính mắc >< chống đối)."}, {"id": "takien", "ten": "Tà kiến", "pali": "Diṭṭhi", "nhom": "batthien_rieng", "giaithich": "Thấy sai, chấp thủ quan điểm lệch lạc — chỉ đồng sinh với 4 tâm Tham \"hợp tà kiến\". Không bao giờ đồng sinh với Mạn vì hai tâm sở này loại trừ nhau: Tà kiến là chấp \"có ta/của ta\" theo tà thuyết, còn Mạn là so sánh hơn/kém/bằng dựa trên ý niệm về một \"cái ta\" đã có sẵn — khi tà kiến hiện diện, cách nhìn về \"ta\" đã khác nên Mạn không có chỗ khởi cùng lúc."}, {"id": "man", "ten": "Mạn", "pali": "Māna", "nhom": "batthien_rieng", "giaithich": "Kiêu mạn, so sánh hơn — thua — bằng. Bất định (không luôn có mặt), chỉ có thể khởi cùng 4 tâm Tham \"ly tà kiến\" (không hợp tà kiến), vì lý do loại trừ lẫn nhau với Tà kiến đã nêu ở trên."}, {"id": "san", "ten": "Sân", "pali": "Dosa", "nhom": "batthien_rieng", "giaithich": "Chống đối, ác cảm, khó chịu với cảnh — chi pháp riêng của 2 tâm Sân, luôn đi với cảm thọ Ưu (domanassa)."}, {"id": "tat", "ten": "Tật", "pali": "Issā", "nhom": "batthien_rieng", "giaithich": "Ganh tỵ với sự hơn của người khác. Bất định, chỉ khởi với tâm Sân, và luôn khởi riêng lẻ — không đồng sinh cùng lúc với Lận hay Hối trong cùng một sát-na."}, {"id": "lan", "ten": "Lận", "pali": "Macchariya", "nhom": "batthien_rieng", "giaithich": "Bỏn xẻn, che giấu sự may mắn/lợi đắc của mình. Bất định, chỉ khởi với tâm Sân, khởi riêng lẻ (không cùng lúc với Tật hay Hối)."}, {"id": "hoi", "ten": "Hối", "pali": "Kukkucca", "nhom": "batthien_rieng", "giaithich": "Ăn năn, hối tiếc về điều ác đã làm hoặc điều thiện chưa làm. Bất định, chỉ khởi với tâm Sân, khởi riêng lẻ (không cùng lúc với Tật hay Lận)."}, {"id": "hontram", "ten": "Hôn trầm", "pali": "Thīna", "nhom": "batthien_rieng", "giaithich": "Làm cho tâm nặng nề, lười biếng, dã dượi. Luôn đồng sinh cùng Thụy miên, và chỉ có mặt trong các tâm bất thiện \"hữu trợ\" (do người khác/hoàn cảnh tác động, cần nhắc nhở hoặc chuẩn bị mới khởi) — không có ở tâm \"vô trợ\" (tự phát)."}, {"id": "thuymien", "ten": "Thụy miên", "pali": "Middha", "nhom": "batthien_rieng", "giaithich": "Làm cho các tâm sở nặng nề, díu lại. Luôn đồng sinh cùng Hôn trầm, chỉ có ở tâm bất thiện hữu trợ."}, {"id": "hoainghi", "ten": "Hoài nghi", "pali": "Vicikicchā", "nhom": "batthien_rieng", "giaithich": "Lưỡng lự, phân vân, không quyết định được — chi pháp riêng của 1 tâm Si duy nhất. Vì bản chất là không thể quyết đoán, tâm này loại trừ hẳn Thắng giải (Adhimokkha), Hỷ và Dục (khi còn hoài nghi thì không thể có hoan hỷ hay ý muốn hành động rõ ràng)."}, {"id": "tin", "ten": "Tín", "pali": "Saddhā", "nhom": "tinhhao_bh", "giaithich": "Niềm tin trong sạch vào những điều đáng tin (Tam Bảo, nghiệp báo...). Một trong 19 tâm sở Tịnh hảo Biến hành, luôn có mặt trong toàn bộ 91 tâm tịnh hảo."}, {"id": "niem", "ten": "Niệm", "pali": "Sati", "nhom": "tinhhao_bh", "giaithich": "Ghi nhớ chân chánh, không lơ đễnh, canh giữ tâm khỏi các pháp bất thiện."}, {"id": "hiri", "ten": "Tàm", "pali": "Hirī", "nhom": "tinhhao_bh", "giaithich": "Hổ thẹn với việc làm điều ác — đối nghịch trực tiếp với Vô tàm bên phía bất thiện."}, {"id": "ottapa", "ten": "Quý", "pali": "Ottappa", "nhom": "tinhhao_bh", "giaithich": "Ghê sợ hậu quả của điều ác — đối nghịch trực tiếp với Vô quý."}, {"id": "votham", "ten": "Vô tham", "pali": "Alobha", "nhom": "tinhhao_bh", "giaithich": "Không dính mắc, biết đủ, xả ly — đối nghịch trực tiếp với Tham."}, {"id": "vosan", "ten": "Vô sân", "pali": "Adosa", "nhom": "tinhhao_bh", "giaithich": "Không chống đối, có thể biểu hiện thành Từ tâm (mettā) — đối nghịch trực tiếp với Sân."}, {"id": "hanhxa", "ten": "Hành xả", "pali": "Tatramajjhattatā", "nhom": "tinhhao_bh", "giaithich": "Sự quân bình giữa tâm và các tâm sở, không thiên lệch — khác với Xả thọ (upekkhā-vedanā, một loại cảm thọ); đây là một tâm sở riêng biệt giữ thăng bằng nội tâm."}, {"id": "antinhthan", "ten": "An tịnh thân (sở hữu)", "pali": "Kāya-passaddhi", "nhom": "tinhhao_bh", "giaithich": "Sự an tịnh của nhóm tâm sở (\"thân\" ở đây nghĩa là tập hợp tâm sở, không phải thân thể vật lý)."}, {"id": "antinhtam", "ten": "An tịnh tâm", "pali": "Citta-passaddhi", "nhom": "tinhhao_bh", "giaithich": "Sự an tịnh của chính tâm (citta)."}, {"id": "khinhthan", "ten": "Khinh thân (sở hữu)", "pali": "Kāya-lahutā", "nhom": "tinhhao_bh", "giaithich": "Sự nhẹ nhàng của nhóm tâm sở, không nặng nề, trì trệ."}, {"id": "khinhtam", "ten": "Khinh tâm", "pali": "Citta-lahutā", "nhom": "tinhhao_bh", "giaithich": "Sự nhẹ nhàng của tâm."}, {"id": "nhuthan", "ten": "Nhu thân (sở hữu)", "pali": "Kāya-mudutā", "nhom": "tinhhao_bh", "giaithich": "Sự mềm mại, uyển chuyển của nhóm tâm sở, không cứng nhắc."}, {"id": "nhutam", "ten": "Nhu tâm", "pali": "Citta-mudutā", "nhom": "tinhhao_bh", "giaithich": "Sự mềm mại, uyển chuyển của tâm."}, {"id": "thichthan", "ten": "Thích thân (sở hữu)", "pali": "Kāya-kammaññatā", "nhom": "tinhhao_bh", "giaithich": "Sự thích nghi, dễ sử dụng của nhóm tâm sở khi hành thiện."}, {"id": "thichtam", "ten": "Thích tâm", "pali": "Citta-kammaññatā", "nhom": "tinhhao_bh", "giaithich": "Sự thích nghi, dễ sử dụng của tâm khi hành thiện."}, {"id": "thuanthan", "ten": "Thuần thân (sở hữu)", "pali": "Kāya-pāguññatā", "nhom": "tinhhao_bh", "giaithich": "Sự thuần thục, thông thạo của nhóm tâm sở."}, {"id": "thuantam", "ten": "Thuần tâm", "pali": "Citta-pāguññatā", "nhom": "tinhhao_bh", "giaithich": "Sự thuần thục, thông thạo của tâm."}, {"id": "chanhthan", "ten": "Chánh thân (sở hữu)", "pali": "Kāya-ujukatā", "nhom": "tinhhao_bh", "giaithich": "Sự ngay thẳng của nhóm tâm sở, không quanh co giả dối."}, {"id": "chanhtam", "ten": "Chánh tâm", "pali": "Citta-ujukatā", "nhom": "tinhhao_bh", "giaithich": "Sự ngay thẳng của tâm."}, {"id": "chanhngu", "ten": "Chánh ngữ", "pali": "Sammā-vācā", "nhom": "tietche", "giaithich": "Tránh xa lời nói sai trái (nói dối, nói đâm thọc, nói thô ác, nói vô ích). Ở Dục giới chỉ khởi riêng lẻ, bất định (tùy hoàn cảnh có cơ hội tránh ác ngữ hay không); ở Siêu thế thì cả 3 Tiết chế luôn đồng sinh cố định cùng lúc vì Đạo Siêu thế đoạn trừ trọn vẹn cả 3 loại ác nghiệp một lần."}, {"id": "chanhnghiep", "ten": "Chánh nghiệp", "pali": "Sammā-kammanta", "nhom": "tietche", "giaithich": "Tránh xa hành động sai trái (sát sanh, trộm cắp, tà dâm). Quy luật đồng sinh giống Chánh ngữ."}, {"id": "chanhmang", "ten": "Chánh mạng", "pali": "Sammā-ājīva", "nhom": "tietche", "giaithich": "Tránh xa nuôi mạng sai trái (lừa đảo, mưu sinh bất chính). Quy luật đồng sinh giống Chánh ngữ."}, {"id": "bi", "ten": "Bi", "pali": "Karuṇā", "nhom": "voluong", "giaithich": "Lòng thương xót trước cảnh khổ của chúng sinh. Bất định — chỉ khởi khi tâm hướng đến một chúng sinh đang khổ làm đối tượng, nên không thể có mặt ở tâm Ngũ song thức/Vô nhân, ở tâm Siêu thế (đối tượng là Níp-bàn, không phải chúng sinh) hay ở tầng thiền thứ 5/Vô sắc giới (quá vi tế, thuần xả)."}, {"id": "tuyhy", "ten": "Tùy hỷ", "pali": "Muditā", "nhom": "voluong", "giaithich": "Vui theo sự thành công, hạnh phúc của người khác. Cùng quy luật đồng sinh như Bi — không cùng lúc với Bi (tùy vào cảnh là chúng sinh khổ hay chúng sinh đang hạnh phúc)."}, {"id": "tue", "ten": "Tuệ quyền (Trí tuệ)", "pali": "Paññā", "nhom": "tuequyen", "giaithich": "Hiểu biết thấu suốt thực tánh pháp — chỉ có ở các tâm \"hợp trí\" (ñāṇasampayutta). Đây là chi pháp chung của 4 quyền Tuệ/Tri vị tri/Tri dĩ tri/Tri cụ tri trong 22 Quyền.", "socount": 79, "quyluat": "12 tâm Dục giới tịnh hảo hợp trí + 27 tâm Đáo đại (Sắc giới + Vô sắc giới, luôn hợp trí) + 40 tâm Siêu thế (luôn hợp trí)."}];
